import { useState, useEffect } from 'react';

export default function ProductModal({ open, product, onClose, onSave }) {
  const [form, setForm] = useState({
    title: '',
    category: '',
    description: '',
    price: '',
    stock: ''
  });

  useEffect(() => {
    if (product) {
      setForm(product);
    } else {
      setForm({ title: '', category: '', description: '', price: '', stock: '' });
    }
  }, [product]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const data = {
      title: form.title.trim(),
      category: form.category.trim(),
      description: form.description.trim(),
      price: Number(form.price),
      stock: Number(form.stock)
    };

    try {
      const url = product ? `/api/products/${product.id}` : '/api/products';
      const method = product ? 'PATCH' : 'POST';

      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data)
      });

      if (!res.ok) throw new Error('Ошибка сервера');

      onSave();
    } catch (err) {
      console.error(err);
      alert('Не удалось сохранить. Проверьте данные и сервер.');
    }
  };

  if (!open) return null;

  return (
    <div className="modal-overlay">
      <div className="modal">
        <h2>{product ? 'Редактировать позицию' : 'Новая позиция в меню'}</h2>

        <form onSubmit={handleSubmit}>
          <label>
            Название:
            <input
              name="title"
              value={form.title}
              onChange={handleChange}
              required
            />
          </label>

          <label>
            Категория:
            <input
              name="category"
              value={form.category}
              onChange={handleChange}
              required
            />
          </label>

          <label>
            Описание:
            <textarea
              name="description"
              value={form.description}
              onChange={handleChange}
              required
            />
          </label>

          <label>
            Цена (₽):
            <input
              type="number"
              name="price"
              value={form.price}
              onChange={handleChange}
              min="1"
              required
            />
          </label>

          <label>
            Остаток:
            <input
              type="number"
              name="stock"
              value={form.stock}
              onChange={handleChange}
              min="0"
              required
            />
          </label>

          <div className="modal-buttons">
            <button type="submit" className="btn primary">Сохранить</button>
            <button type="button" className="btn secondary" onClick={onClose}>
              Отмена
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
